import React, { useState } from "react";
import { uploadFile, fetchGoogleSheet } from "../services/api";

function Upload({ setUrls }) {
  const [file, setFile] = useState(null);
  const [sheetUrl, setSheetUrl] = useState("");

  const handleUpload = async () => {
    const res = await uploadFile(file);
    setUrls(res.data.urls);
  };

  const handleGoogleSheet = async () => {
  console.log("Sending URL:", sheetUrl); // 👈 ADD THIS

  if (!sheetUrl) {
    alert("Enter URL first");
    return;
  }

  try {
    const res = await fetchGoogleSheet(sheetUrl);
    setUrls(res.data.urls);
  } catch (err) {
    console.error("Frontend Error:", err.response?.data || err.message);
  }
};

  return (
    <div>
      <input type="file" onChange={(e) => setFile(e.target.files[0])} />
      <button type="button" onClick={handleUpload}>Upload File</button>
      <br /><br />

      <input
        type="text"
        placeholder="Paste Google Sheet URL"
        value={sheetUrl}
        onChange={(e) => setSheetUrl(e.target.value)}
      />
      <button onClick={handleGoogleSheet}>Load Sheet</button>
    </div>
  );
}

export default Upload;
